num = 29
for i in range(2, num):
    if num % i == 0:
        print('Not prime')
        break
else:
    print('Prime')

def reverse():
    stop = False
    while stop != True:
        text = input('Enter text: ')
        print(text[::-1])
        again = input('Again? (Y/N) ')
        if again.upper() == 'Y':
            continue
        else:
            print('Goodbye!')
            stop = True

reverse()

